function createOverlayThemeController(root, config, helpers){
  let intervalId = null;
  let currentConfig = {...(config || {})};
  let remaining = 0;

  function clamp(n){
    return Number.isFinite(n) && n >= 0 ? Math.floor(n) : 0;
  }

  function readDuration(cfg){
    const h = clamp(Number(cfg.hours ?? 0));
    const m = clamp(Number(cfg.minutes ?? 0));
    const s = clamp(Number(cfg.seconds ?? 0));
    return h * 3600 + m * 60 + s;
  }

  function pad(v){
    return String(v).padStart(2, '0');
  }

  function render(){
    const h = Math.floor(remaining / 3600);
    const m = Math.floor((remaining % 3600) / 60);
    const s = Math.floor(remaining % 60);
    helpers.setText('#timer-h', pad(h));
    helpers.setText('#timer-m', pad(m));
    helpers.setText('#timer-s', pad(s));
  }

  function start(){
    if(intervalId) return;
    intervalId = setInterval(() => {
      if(remaining <= 0){
        stop();
        return;
      }
      remaining -= 1;
      render();
    }, 1000);
  }

  function stop(){
    if(intervalId){
      clearInterval(intervalId);
      intervalId = null;
    }
  }

  function restart(){
    stop();
    remaining = readDuration(currentConfig);
    render();
    start();
  }

  function updateConfig(next){
    currentConfig = {...(next || {})};
    if(!intervalId){
      remaining = readDuration(currentConfig);
      render();
    }
  }

  remaining = readDuration(currentConfig);
  render();

  return { start, stop, restart, updateConfig, destroy: stop };
}
